public class Blockchain {
 private Map<String, Boolean> rules;
 private List<Block> chain;

 public Blockchain(Map<String, Boolean> rules) {
 this.rules = rules;
 this.chain = new ArrayList<>();
 }

 public void applySoftFork(Map<String, Boolean> newRules) {
 // Apply soft fork logic
 this.rules = newRules;
 }

 public void applyHardFork(Map<String, Boolean> newRules) {
 // Apply hard fork logic
 this.chain = new ArrayList<>();
 this.rules = newRules;
 }
}

// Create a blockchain with initial rules
Map<String, Boolean> rules = new HashMap<>();
rules.put("rule1", true);
rules.put("rule2", false);
Blockchain blockchain = new Blockchain(rules);

// Apply a soft fork
Map<String, Boolean> newRules = new HashMap<>();
newRules.put("rule1", true);
newRules.put("rule2", true);
blockchain.applySoftFork(newRules);

// Apply a hard fork
newRules = new HashMap<>();
newRules.put("rule1", false);
newRules.put("rule2", true);
blockchain.applyHardFork(newRules);
